import{_ as e,c as t,o as s,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Часто задаваемые вопросы: Устранение неполадок и безопасность | opencode-agent-skills","description":"Узнайте о распространенных проблемах и механизмах безопасности при использовании плагина. Изучите методы устранения неполадок при сбоях загрузки навыков, ошибках скриптов, а также основные механизмы защиты безопасности, такие как проверка путей и валидация входных данных.","frontmatter":{"title":"Часто задаваемые вопросы: Устранение неполадок и безопасность | opencode-agent-skills","sidebarTitle":"Что делать при возникновении проблем","subtitle":"Часто задаваемые вопросы: Устранение неполадок и безопасность","description":"Узнайте о распространенных проблемах и механизмах безопасности при использовании плагина. Изучите методы устранения неполадок при сбоях загрузки навыков, ошибках скриптов, а также основные механизмы защиты безопасности, такие как проверка путей и валидация входных данных.","order":4},"headers":[],"relativePath":"ru/joshuadavidthomas/opencode-agent-skills/faq/index.md","filePath":"ru/joshuadavidthomas/opencode-agent-skills/faq/index.md"}'),l={name:"ru/joshuadavidthomas/opencode-agent-skills/faq/index.md"};function r(i,a,n,d,c,p){return s(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="часто-задаваемые-вопросы" tabindex="-1">Часто задаваемые вопросы <a class="header-anchor" href="#часто-задаваемые-вопросы" aria-label="Permalink to &quot;Часто задаваемые вопросы&quot;">​</a></h1><p>Этот раздел поможет вам решить проблемы, возникающие при использовании плагина OpenCode Agent Skills, и познакомит с механизмами безопасности плагина. Будь то сбой загрузки навыка, ошибка выполнения скрипта или желание узнать, как плагин защищает вашу систему, — здесь вы найдете ответы.</p><h2 id="содержание-главы" tabindex="-1">Содержание главы <a class="header-anchor" href="#содержание-главы" aria-label="Permalink to &quot;Содержание главы&quot;">​</a></h2><div class="grid grid-cols-1 md:grid-cols-2 gap-4 mt-6"><a href="./troubleshooting/" class="block p-4 border rounded-lg hover:border-brand-500 transition-colors no-underline"><h3 class="text-lg font-semibold mb-2">🔧 Устранение распространенных проблем</h3><p class="text-sm text-gray-600 dark:text-gray-400">Решение проблем с загрузкой навыков, ошибками выполнения скриптов, проблемами безопасности путей, сбоями загрузки моделей и другими 9 типами распространенных проблем.</p></a><a href="./security-considerations/" class="block p-4 border rounded-lg hover:border-brand-500 transition-colors no-underline"><h3 class="text-lg font-semibold mb-2">🔒 Механизмы безопасности</h3><p class="text-sm text-gray-600 dark:text-gray-400">Узнайте о ключевых механизмах безопасности плагина, включая проверку путей, безопасный парсинг YAML, валидацию входных данных, защиту выполнения скриптов и лучшие практики.</p></a></div><h2 id="путь-обучения" tabindex="-1">Путь обучения <a class="header-anchor" href="#путь-обучения" aria-label="Permalink to &quot;Путь обучения&quot;">​</a></h2><p>Рекомендуется изучать материалы этого раздела в следующем порядке:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Устранение распространенных проблем → Механизмы безопасности</span></span></code></pre></div><ol><li><strong>Сначала изучите устранение неполадок</strong>: при возникновении проблем сначала обратитесь к разделу «Устранение распространенных проблем» для быстрого выявления и решения</li><li><strong>Затем изучите безопасность</strong>: ознакомьтесь с механизмами безопасности плагина, чтобы выработать безопасные привычки использования</li></ol><div class="tip custom-block"><p class="custom-block-title">Что делать при возникновении проблем</p><p>Если вы столкнулись с конкретной проблемой при использовании плагина, сразу перейдите к разделу «Устранение распространенных проблем» и найдите соответствующие симптомы. Если вы хотите системно ознакомиться с проектом безопасности плагина, прочитайте раздел «Механизмы безопасности».</p></div><h2 id="предварительные-требования" tabindex="-1">Предварительные требования <a class="header-anchor" href="#предварительные-требования" aria-label="Permalink to &quot;Предварительные требования&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Рекомендуется сначала завершить следующие разделы</p><ul><li><a href="./../start/">Руководство по началу работы</a>: ознакомьтесь с основными концепциями и методами установки плагина</li><li><a href="./../platforms/">Платформы и интеграции</a>: изучите ключевые функции, такие как обнаружение, загрузка и выполнение навыков</li></ul><p>Содержание этого раздела предполагает, что вы уже имеете базовое представление о плагине. Если вы используете его впервые, рекомендуется сначала изучить указанные выше разделы.</p></div><h2 id="следующии-шаг" tabindex="-1">Следующий шаг <a class="header-anchor" href="#следующии-шаг" aria-label="Permalink to &quot;Следующий шаг&quot;">​</a></h2><p>После завершения изучения этого раздела вы можете продолжить изучение:</p><ul><li><strong><a href="./../appendix/">Приложения</a></strong>: ознакомьтесь с лучшими практиками разработки навыков и справочником по инструментам API</li><li><strong><a href="./../changelog/">Журнал изменений</a></strong>: узнайте о версиях плагина и новых функциях</li></ul>',14)])])}const g=e(l,[["render",r]]);export{u as __pageData,g as default};
